import React, { useEffect } from 'react';
import { BrowserRouter as Router, Routes, Route, Navigate } from 'react-router-dom';
import './App.css';
import { AuthProvider, useAuth } from './contexts/AuthContext';
import Header from './components/Header';
import Sidebar from './components/Sidebar';
import ProtectedRoute from './components/ProtectedRoute';
import Login from './pages/Login';
import EmployeeManagement from './pages/Employees';
import PlanningGenerator from './pages/Planning';
import ConstraintsManager from './pages/Constraints';
import Dashboard from './pages/Dashboard';
import SalesStats from './pages/SalesStats';
import AbsenceStatusPage from './pages/AbsenceStatusPage';
import MealExpenses from './pages/MealExpenses';
import KmExpenses from './pages/KmExpenses';
import Parameters from './pages/Parameters';
import EmployeeStatusPrint from './pages/EmployeeStatusPrint';
import Tutors from './pages/Tutors';
// import SickLeaveUpload from './pages/SickLeaveUpload'; // Non utilisé
import SickLeaveUploadStandalone from './pages/SickLeaveUploadStandalone';
import SickLeaveAdmin from './pages/SickLeaveAdmin';
import SickLeaveHome from './pages/SickLeaveHome';
import VacationRequestAdmin from './pages/VacationRequestAdmin';
import VacationPlanning from './pages/VacationPlanning';
import TicketRestaurant from './pages/TicketRestaurant';
import EmployeeDashboard from './pages/EmployeeDashboard';
import AdvanceRequests from './pages/AdvanceRequests';
import Recup from './pages/Recup';
import Primes from './pages/Primes';
import MutuelleManagement from './pages/MutuelleManagement';
import Ambassadeur from './pages/Ambassadeur';
import CommandesEnLigne from './pages/CommandesEnLigne';
import CommandeLivraisonEntreprises from './pages/CommandeLivraisonEntreprises';
import ProductExchanges from './pages/ProductExchanges';
import ResponsableKmExpenses from './pages/ResponsableKmExpenses';
import DeplacementStandalone from './pages/DeplacementStandalone';
import PlateauxRepas from './pages/PlateauxRepas';
import PlateauxRepasStandalone from './pages/PlateauxRepasStandalone';
import Chorus from './pages/Chorus';
import Vehicle from './pages/Vehicle';
import VehicleStandalone from './pages/VehicleStandalone';
import CompteClientStandalone from './pages/CompteClientStandalone';
import CompteClientDepots from './pages/CompteClientDepots';
import StandaloneMenu from './pages/StandaloneMenu';
import Stocks from './pages/Stocks';
import StocksFarinesStandalone from './pages/StocksFarinesStandalone';
import MenuPermissionGate from './components/MenuPermissionGate';
import Positive from './pages/Positive';
import CommandeTGT from './pages/CommandeTGT';
import { getSiteBasename } from './config/site';

const AppContent = () => {
  const { user, loading } = useAuth();

  // Éviter le flash Login au refresh : attendre le chargement du user depuis localStorage
  if (loading) {
    return (
      <div style={{ display: 'flex', justifyContent: 'center', alignItems: 'center', height: '100vh', fontSize: '1.2rem', color: '#666' }}>
        Chargement...
      </div>
    );
  }
  if (!user) {
    return <Login />;
  }

  return (
      <div className="App">
      <Header />
      <div className="app-container">
        <Sidebar />
        <main className="app-main">
          <Routes>
            <Route path="/" element={<Navigate to="/dashboard" replace />} />
            <Route path="/dashboard" element={
              <ProtectedRoute>
                <Dashboard />
              </ProtectedRoute>
            } />
            <Route path="/employees" element={
              <ProtectedRoute>
                <EmployeeManagement />
              </ProtectedRoute>
            } />
            <Route path="/constraints" element={
              <ProtectedRoute>
                <ConstraintsManager />
              </ProtectedRoute>
            } />
            <Route path="/planning" element={
              <ProtectedRoute requiredPermission="view_planning">
                <PlanningGenerator />
              </ProtectedRoute>
            } />
            <Route path="/sales-stats" element={
              <ProtectedRoute requiredPermission="view_sales_stats">
                <SalesStats />
              </ProtectedRoute>
            } />
            <Route path="/absences" element={
              <ProtectedRoute requiredPermission="view_absences">
                <AbsenceStatusPage />
              </ProtectedRoute>
            } />
            <Route path="/meal-expenses" element={
              <ProtectedRoute requiredPermission="view_meal_expenses">
                <MealExpenses />
              </ProtectedRoute>
            } />
            <Route path="/km-expenses" element={
              <ProtectedRoute requiredPermission="view_km_expenses">
                <KmExpenses />
              </ProtectedRoute>
            } />
            <Route path="/parameters" element={
              <ProtectedRoute adminOnly={true}>
                <Parameters />
              </ProtectedRoute>
            } />
            <Route path="/stocks" element={
              <ProtectedRoute>
                <MenuPermissionGate menuId="stocks">
                  <Stocks />
                </MenuPermissionGate>
              </ProtectedRoute>
            } />
            <Route path="/positive" element={
              <ProtectedRoute>
                <Positive />
              </ProtectedRoute>
            } />
            <Route path="/commande-tgt" element={
              <ProtectedRoute>
                <MenuPermissionGate menuId="commande-tgt">
                  <CommandeTGT />
                </MenuPermissionGate>
              </ProtectedRoute>
            } />
            <Route path="/employee-status-print" element={
              <ProtectedRoute>
                <EmployeeStatusPrint />
              </ProtectedRoute>
            } />
            <Route path="/tutors" element={
              <ProtectedRoute adminOnly={true}>
                <Tutors />
              </ProtectedRoute>
            } />
            <Route path="/sick-leave" element={<Navigate to="/plan/sick-leave" replace />} />
            <Route path="/plan/sick-leave" element={<SickLeaveHome />} />
            <Route path="/sick-leave-upload" element={<SickLeaveUploadStandalone />} />
            <Route path="/plan/sick-leave-upload" element={<SickLeaveUploadStandalone />} />
            <Route path="/sick-leave-management" element={
              <ProtectedRoute adminOnly={true}>
                <SickLeaveAdmin />
              </ProtectedRoute>
            } />
            <Route path="/vacation-management" element={
              <ProtectedRoute adminOnly={true}>
                <VacationRequestAdmin />
              </ProtectedRoute>
            } />
            <Route path="/vacation-planning" element={
              <ProtectedRoute>
                <VacationPlanning />
              </ProtectedRoute>
            } />
            <Route path="/ticket-restaurant" element={
              <ProtectedRoute>
                <TicketRestaurant />
              </ProtectedRoute>
            } />
            <Route path="/employee-dashboard" element={
              <ProtectedRoute>
                <EmployeeDashboard />
              </ProtectedRoute>
            } />
            <Route path="/advance-requests" element={
              <ProtectedRoute>
                <AdvanceRequests />
              </ProtectedRoute>
            } />
            <Route path="/recup" element={
              <ProtectedRoute>
                <Recup />
              </ProtectedRoute>
            } />
            <Route path="/primes" element={
              <ProtectedRoute adminOnly={true}>
                <Primes />
              </ProtectedRoute>
            } />
            <Route path="/mutuelle-management" element={
              <ProtectedRoute adminOnly={true}>
                <MutuelleManagement />
              </ProtectedRoute>
            } />
            <Route path="/ambassadeur" element={
              <ProtectedRoute>
                <Ambassadeur />
              </ProtectedRoute>
            } />
            <Route path="/commandes-en-ligne" element={
              <ProtectedRoute>
                <CommandesEnLigne />
              </ProtectedRoute>
            } />
            <Route path="/commande-livraison" element={
              <ProtectedRoute>
                <CommandeLivraisonEntreprises />
              </ProtectedRoute>
            } />
            <Route path="/product-exchanges" element={
              <ProtectedRoute>
                <ProductExchanges />
              </ProtectedRoute>
            } />
            <Route path="/frais-km-responsable" element={
              <ProtectedRoute adminOnly={true}>
                <ResponsableKmExpenses />
              </ProtectedRoute>
            } />
            <Route path="/plateaux-repas" element={
              <ProtectedRoute>
                <PlateauxRepas />
              </ProtectedRoute>
            } />
            <Route path="/chorus" element={
              <ProtectedRoute adminOnly={true}>
                <Chorus />
              </ProtectedRoute>
            } />
            <Route path="/vehicle" element={
              <ProtectedRoute adminOnly={true}>
                <Vehicle />
              </ProtectedRoute>
            } />
            <Route path="/compte-client-depots" element={
              <ProtectedRoute adminOnly={true}>
                <CompteClientDepots />
              </ProtectedRoute>
            } />
          </Routes>
        </main>
      </div>
    </div>
  );
};

// Redirection complète (rechargement page) vers la page standalone - évite le mot de passe planning
const AmbassadeurStandaloneRedirect = () => {
  useEffect(() => {
    const base = window.location.pathname.startsWith('/lon') ? '/lon' : '/plan';
    window.location.replace(`${window.location.origin}${base}/ambassadeur-standalone.html`);
  }, []);
  return (
    <div style={{ padding: 40, textAlign: 'center', fontFamily: 'sans-serif' }}>
      Redirection vers la page Ambassadeur…
    </div>
  );
};

function App() {
  const getBasename = () => {
    // Basename déterminé de façon robuste (fallback localStorage si le préfixe disparaît au refresh)
    return getSiteBasename() || (import.meta.env.BASE_URL || '/plan');
  };

  return (
    <AuthProvider>
      <Router basename={getBasename()}>
        <Routes>
          <Route path="/ambassadeur-standalone" element={<AmbassadeurStandaloneRedirect />} />
          <Route path="/login" element={<Login />} />
          <Route path="/deplacement-standalone" element={<DeplacementStandalone />} />
          <Route path="/deplacement-standalone.html" element={<DeplacementStandalone />} />
          <Route path="/stocks-farines-standalone" element={<StocksFarinesStandalone />} />
          <Route path="/stocks-farines-standalone.html" element={<StocksFarinesStandalone />} />
          <Route path="/plateaux-repas-standalone" element={<PlateauxRepasStandalone />} />
          <Route path="/plateaux-repas-standalone.html" element={<PlateauxRepasStandalone />} />
          <Route path="/vehicle-standalone" element={<VehicleStandalone />} />
          <Route path="/vehicle-standalone.html" element={<VehicleStandalone />} />
          <Route path="/compte-client-standalone" element={<CompteClientStandalone />} />
          <Route path="/compte-client-standalone.html" element={<CompteClientStandalone />} />
          <Route path="/menu-standalone" element={<StandaloneMenu />} />
          <Route path="/menu-standalone.html" element={<StandaloneMenu />} />
          <Route path="/*" element={<AppContent />} />
        </Routes>
    </Router>
    </AuthProvider>
  );
}

export default App;

